class HeatingPlan {
    boolean withinRange(int low, int high) {
        return low >= this.rangeMin && high <= this.rangeMax;
    }
}

// caller decomposes the object before passing
void checkTemperatureRange(Room room, HeatingPlan plan) {
    int low = room.getDaysTempRange().getLow();
    int high = room.getDaysTempRange().getHigh();
    if (!plan.withinRange(low, high)) {
        alerts.add("Room temperature outside heating plan range");
    }
}
